/**
 * api.js — CMIP Data Layer (static JSON snapshot edition)
 *
 * Responsibilities:
 *  - Fetch all data from STATIC JSON files published next to the site
 *    (assets/data/<sheet>.json), generated by the snapshot GitHub Action.
 *  - Same-origin fetch → no CORS, no JSONP, no Apps Script redirect, and no
 *    Google-account dependency. Works identically for every visitor, signed
 *    in or not (this is what fixed the mobile "unable to open the file" issue).
 *  - In-memory cache with configurable TTL (avoids re-fetching on tab switches).
 *  - Client-side filtering (day / section / category) — the static files hold
 *    the full sheet, so filtering that Apps Script used to do server-side now
 *    happens here. Public function signatures are unchanged, so ui.js is untouched.
 *  - Fallback placeholder data for offline development via file:// (where
 *    fetch() of local files is blocked by the browser).
 *
 * The live browser NEVER contacts Apps Script. Content flow is:
 *   Google Sheet → snapshot Action → assets/data/*.json → this module → ui.js
 *
 * Persidangan Kebangsaan Penguatkuasaan Jenayah Farmaseutikal 2026
 */

'use strict';

import { API } from './config.js?v=4';

/** Base path for the published JSON snapshot (configurable via config.js). */
const DATA_BASE = (API && API.DATA_BASE) || './assets/data/';


/* ============================================================
   IN-MEMORY CACHE
   Structure: { [sheet]: { data: any, expiresAt: number } }
   ============================================================ */
const _cache = new Map();

/** Read from cache. Returns data if fresh, null if expired/missing. */
function cacheGet(key) {
  const entry = _cache.get(key);
  if (!entry) return null;
  if (Date.now() > entry.expiresAt) {
    _cache.delete(key);
    return null;
  }
  return entry.data;
}

/** Write to cache with TTL (defaults to API.CACHE_TTL). */
function cacheSet(key, data, ttl = API.CACHE_TTL) {
  _cache.set(key, { data, expiresAt: Date.now() + ttl });
}

/** Manually clear one cache entry (e.g., after a forced refresh). */
export function cacheClear(key) {
  _cache.delete(key);
}

/** Clear all cached data. */
export function cacheClearAll() {
  _cache.clear();
}


/* ============================================================
   DEV MODE DETECTION
   Only file:// needs fallback data — the browser blocks fetch()
   of local files there. On http(s) (localhost or production) the
   real JSON snapshot is fetched normally.
   ============================================================ */
const IS_FILE = window.location.protocol === 'file:';

/** Returns true when static JSON cannot be fetched and fallback is needed. */
function useFallback() {
  return IS_FILE;
}


/* ============================================================
   CORE FETCH — static JSON, same-origin
   Loads the FULL sheet; public functions filter client-side.
   ============================================================ */

/**
 * Fetch a full sheet as an array of row objects from its static JSON file.
 * @param {string} sheet — sheet name (from API.SHEETS), e.g. 'faq'
 * @returns {Promise<Array|Object>}
 * @throws {ApiError}
 */
async function fetchSheet(sheet) {
  // Return cached result if fresh
  const cached = cacheGet(sheet);
  if (cached !== null) {
    console.debug(`[CMIP] cache-hit ${sheet}`);
    return cached;
  }

  // Offline (file://) → placeholder data
  if (useFallback()) {
    console.warn(`[CMIP] fallback (file://) for ${sheet}`);
    const fb = getFallbackData(sheet);
    cacheSet(sheet, fb);
    return fb;
  }

  const url = `${DATA_BASE}${sheet}.json`;
  console.debug(`[CMIP] fetch ${url}`);

  let res;
  try {
    // no-cache = always revalidate against GitHub Pages' ETag, so visitors
    // never get stale data, but unchanged files return a fast 304.
    res = await fetch(url, { cache: 'no-cache' });
  } catch (err) {
    throw new ApiError(`Network error loading "${sheet}"`, 0, sheet);
  }
  if (!res.ok) {
    throw new ApiError(`HTTP ${res.status} loading "${sheet}"`, res.status, sheet);
  }

  let data;
  try {
    data = await res.json();
  } catch (err) {
    throw new ApiError(`Invalid JSON for "${sheet}"`, 0, sheet);
  }

  // Snapshot stores the raw `data` array; tolerate an envelope too.
  const arr = Array.isArray(data) ? data : (data && data.data ? data.data : data);
  cacheSet(sheet, arr);
  return arr;
}


/* ============================================================
   CUSTOM ERROR CLASS
   ============================================================ */
export class ApiError extends Error {
  /**
   * @param {string} message
   * @param {number} status — HTTP status, or 0 for network/parse errors
   * @param {string} sheet  — which sheet was being fetched
   */
  constructor(message, status, sheet) {
    super(message);
    this.name   = 'ApiError';
    this.status = status;
    this.sheet  = sheet;
  }
}


/* ============================================================
   SMALL HELPERS
   ============================================================ */

/** Case-insensitive equality for filtering string fields. */
function eqi(a, b) {
  return String(a == null ? '' : a).trim().toLowerCase() === String(b).trim().toLowerCase();
}


/* ============================================================
   PUBLIC FETCH FUNCTIONS
   One function per data type. Signatures unchanged from the
   JSONP version — filtering now happens client-side.
   ============================================================ */

/**
 * Fetch site configuration from the `config` sheet.
 * Returns a key→value object (all rows merged).
 * @returns {Promise<Object>}
 */
export async function fetchSiteConfig() {
  const rows = await fetchSheet(API.SHEETS.CONFIG);
  if (Array.isArray(rows)) {
    return rows.reduce((acc, row) => {
      if (row.key) acc[row.key] = row.value;
      return acc;
    }, {});
  }
  return rows;
}

/**
 * Fetch programme / agenda rows for a specific day.
 * @param {number} day — 1, 2, or 3
 * @returns {Promise<Array<ProgrammeRow>>}
 */
export async function fetchProgramme(day) {
  const rows = await fetchSheet(API.SHEETS.PROGRAMME);
  if (!Array.isArray(rows)) return [];
  return day ? rows.filter(r => String(r.day) === String(day)) : rows;
}

/**
 * Fetch all programme rows grouped by day: { 1: [...], 2: [...], 3: [...] }
 * @returns {Promise<Object<number, Array<ProgrammeRow>>>}
 */
export async function fetchProgrammeAll() {
  const rows = await fetchSheet(API.SHEETS.PROGRAMME);
  if (!Array.isArray(rows)) return {};
  return rows.reduce((acc, row) => {
    const d = Number(row.day) || 1;
    if (!acc[d]) acc[d] = [];
    acc[d].push(row);
    return acc;
  }, {});
}

/**
 * Fetch all speakers.
 * @returns {Promise<Array<SpeakerRow>>}
 */
export async function fetchSpeakers() {
  return fetchSheet(API.SHEETS.SPEAKERS);
}

/**
 * Fetch RISE entries, optionally filtered by category.
 * @param {string} [category] — '1' | '2' | '3' | undefined (all)
 * @returns {Promise<Array<RiseRow>>}
 */
export async function fetchRise(category) {
  const rows = await fetchSheet(API.SHEETS.RISE);
  if (!Array.isArray(rows)) return [];
  return category ? rows.filter(r => String(r.category) === String(category)) : rows;
}

/**
 * Fetch download items, optionally filtered by section.
 * @param {string} [section] — e.g. 'general' | 'rise' | undefined (all)
 * @returns {Promise<Array<DownloadRow>>}
 */
export async function fetchDownloads(section) {
  const rows = await fetchSheet(API.SHEETS.DOWNLOADS);
  if (!Array.isArray(rows)) return [];
  return section ? rows.filter(r => eqi(r.section, section)) : rows;
}

/**
 * Fetch gallery images.
 * @returns {Promise<Array<GalleryRow>>}
 */
export async function fetchGallery() {
  return fetchSheet(API.SHEETS.GALLERY);
}

/**
 * Fetch FAQ items, optionally filtered by section.
 * @param {string} [section] — e.g. 'general' | 'rise' | undefined (all)
 * @returns {Promise<Array<FaqRow>>}
 */
export async function fetchFaq(section) {
  const rows = await fetchSheet(API.SHEETS.FAQ);
  if (!Array.isArray(rows)) return [];
  return section ? rows.filter(r => eqi(r.section, section)) : rows;
}

/**
 * Fetch sponsors / partners.
 * @returns {Promise<Array<SponsorRow>>}
 */
export async function fetchSponsors() {
  return fetchSheet(API.SHEETS.SPONSORS);
}

/**
 * Fetch contact / committee information.
 * @returns {Promise<Array<ContactRow>>}
 */
export async function fetchContact() {
  return fetchSheet(API.SHEETS.CONTACT);
}


/* ============================================================
   FALLBACK STATIC DATA (file:// development only)
   Returns FULL sets; public functions apply any filtering.
   ============================================================ */

